  const DEFAULT_ARTICLE_READING_PROVIDER = "local";
  const DEFAULT_ARTICLE_AUDIO_CACHE_FOLDER = "ClipLex/Media/ArticleAudioCache";
  const ARTICLE_DEEP_STUDY_LOG_DEFAULT_PATH = "ClipLex/Study/Article Deep Study.md";
  const ARTICLE_TTS_PRELOAD_AHEAD = 1;
  const ARTICLE_TTS_GENERATE_TIMEOUT_MS = 120000;
  const LOCAL_TTS_BOOTSTRAP_TIMEOUT_MS = 900000;
  const KOKORO_MODEL_FILE = "kokoro-v1.0.int8.onnx";
