      new obsidian.Setting(this.contentEl)
        .setName("Auto-start bundled local TTS")
        .setDesc("When the default localhost Kokoro endpoint is selected, Immerse Learning prepares and starts the bundled service automatically.")
        .addToggle((toggle) => {
          toggle
            .setValue(this.plugin.settings.cliplexArticleAutoStartLocalTts !== false)
            .onChange(async (value) => {
              this.plugin.settings.cliplexArticleAutoStartLocalTts = value;
              await this.save();
            });
        });
      new obsidian.Setting(this.contentEl)
        .setName("Local TTS endpoint")
        .setDesc("OpenAI-compatible local speech endpoint. Kokoro FastAPI commonly uses this default.")
        .addText((text) => {
          text
            .setPlaceholder(DEFAULT_ARTICLE_LOCAL_TTS_ENDPOINT)
            .setValue(this.plugin.settings.cliplexArticleLocalTtsEndpoint || DEFAULT_ARTICLE_LOCAL_TTS_ENDPOINT)
            .onChange(async (value) => {
              this.plugin.settings.cliplexArticleLocalTtsEndpoint = value.trim() || DEFAULT_ARTICLE_LOCAL_TTS_ENDPOINT;
              await this.save();
            });
        });
      new obsidian.Setting(this.contentEl)
        .setName("Local model")
        .setDesc("Model name sent to the local TTS server.")
        .addText((text) => {
          text
            .setPlaceholder(DEFAULT_ARTICLE_LOCAL_TTS_MODEL)
            .setValue(this.plugin.settings.cliplexArticleLocalTtsModel || DEFAULT_ARTICLE_LOCAL_TTS_MODEL)
            .onChange(async (value) => {
              this.plugin.settings.cliplexArticleLocalTtsModel = value.trim() || DEFAULT_ARTICLE_LOCAL_TTS_MODEL;
              await this.save();
            });
        });
      new obsidian.Setting(this.contentEl)
        .setName("Local voice")
